TEST_CASE("resume with HYBRID_FLAG_V restores vstart/vxsat/vxrm/vcsr via abstract commands")
{
  RecordingBus bus;
  bus.dmstatus_value = (1u << 9) | (1u << 17);

  auto s = rv64_state(0x80001000, 0);
  s.flags |= HYBRID_FLAG_V;
  s.vstart = 4;
  s.vxsat  = 1;
  s.vxrm   = 2;
  s.vcsr   = 5;

  hybrid::ResumeDriver driver(bus);
  driver.resume(s);

  const auto ns = cmd_regnos(bus.ops);
  CHECK(contains_regno(ns, hybrid::regno_csr(0x008)));  // vstart
  CHECK(contains_regno(ns, hybrid::regno_csr(0x009)));  // vxsat
  CHECK(contains_regno(ns, hybrid::regno_csr(0x00A)));  // vxrm
  CHECK(contains_regno(ns, hybrid::regno_csr(0x00F)));  // vcsr
