  // Test-controlled response values for reads.
  uint32_t dmstatus_value = 0;       // bit 9: allhalted, bit 17: allresumeack
  uint32_t abstractcs_value = 0;     // fallback when queue is empty
  std::deque<uint32_t> abstractcs_queue; // queued reads drain first

  // When set, an abstract write-COMMAND to this CSR regno raises a sticky
  // cmderr (cleared by the W1C abstractcs write the driver issues on its PB
  // fallback). Models real hardware and -- unlike positional queueing -- is
  // robust to however many unrelated abstract ops precede the targeted write.
  std::optional<uint16_t> fail_csr_write;

  void write(uint8_t reg, uint32_t value) override
  {
    ops.push_back({DmiOp::Kind::Write, reg, value});
    if (reg == kAbstractcs && (value & kCmderrMask) != 0u)
      cmderr_sticky_ = false;  // W1C clear
    if (reg == kCommand && fail_csr_write) {
      const auto regno    = static_cast<uint16_t>(value & 0xFFFFu);
      const bool is_write = ((value >> 16) & 1u) != 0u;
      if (is_write && regno == hybrid::regno_csr(*fail_csr_write))
        cmderr_sticky_ = true;
    }
  }

  auto read(uint8_t reg) -> uint32_t override
  {
    ops.push_back({DmiOp::Kind::Read, reg, 0});
    if (reg == kDmstatus) return dmstatus_value;
    if (reg == kAbstractcs) {
      if (cmderr_sticky_) return kCmderrMask;
      if (!abstractcs_queue.empty()) {
        auto v = abstractcs_queue.front();
        abstractcs_queue.pop_front();
        return v;
      }
      return abstractcs_value;
    }
    return 0;
  }

private:
  static constexpr uint32_t kCmderrMask = 0x7u << 8;
  bool cmderr_sticky_ = false;
};

