TEST_CASE("resume with HYBRID_FLAG_V: PB reload sweeps v0..v31 from scratch "
          "before the architectural V-CSR restore and counter restore")
{
  RecordingBus bus;
  bus.dmstatus_value = (1u << 9) | (1u << 17);

  auto s = rv64_state(0x80001000, 0);
  s.flags  |= HYBRID_FLAG_V;
  s.vlenb  = 64;
  s.vl     = 16;
  s.vtype  = 0xC1;   // differs from the sweep's e8/m1 vtype (0xC0)
  s.vstart = 7;

  hybrid::ResumeDriver driver(bus);
  driver.resume(s);

  // (a) every v0..v31 is reloaded via a vle8.v executed in the Program Buffer.
  std::vector<int> missing;
  std::optional<std::size_t> first_vle_idx, last_vle_idx;
  for (uint16_t v = 0; v < 32; ++v) {
    const uint32_t want = hybrid::encode_vle8_v(static_cast<uint8_t>(v), 7);
    std::optional<std::size_t> at;
    for (std::size_t i = 0; i < bus.ops.size(); ++i) {
      const auto& op = bus.ops[i];
      if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
          && op.value == want) { at = i; break; }
    }
    if (!at) { missing.push_back(v); continue; }
    if (!first_vle_idx || *at < *first_vle_idx) first_vle_idx = at;
    if (!last_vle_idx  || *at > *last_vle_idx)  last_vle_idx  = at;
  }
  CHECK(missing.empty());
  REQUIRE(first_vle_idx.has_value());
  REQUIRE(last_vle_idx.has_value());

  // (b) the per-register scratch GPA is staged in x7 (base pointer) for the
  //     first and last register.
  auto x7_gpa_staged = [&](uint64_t gpa) {
    for (std::size_t i = 2; i < bus.ops.size(); ++i) {
      const auto& op = bus.ops[i];
      if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
          && (op.value & 0xFFFFu) == hybrid::regno_gpr(7)
          && ((op.value >> 16) & 1u)) {
        const auto& d0 = bus.ops[i - 2];
        const auto& d1 = bus.ops[i - 1];
        if (d0.reg == kData0 && d0.value == uint32_t(gpa & 0xFFFFFFFFu)
            && d1.reg == kData1 && d1.value == uint32_t(gpa >> 32))
          return true;
      }
    }
    return false;
  };
  CHECK(x7_gpa_staged(hybrid::kVScratchGpa));
  CHECK(x7_gpa_staged(hybrid::kVScratchGpa + 31ull * HYBRID_VLEN_BYTES_MAX));

  // (c)/(d) the sweep runs before the architectural vstart restore (whose
  //     vsetvl would otherwise be clobbered) and before the mcycle restore
  //     (so the vle8.v insns cannot pollute the resumed counters).
  std::optional<std::size_t> vstart_cmd_idx, mcycle_cmd_idx;
  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
    const auto& op = bus.ops[i];
    if (op.kind != DmiOp::Kind::Write || op.reg != kCommand) continue;
    const auto regno = static_cast<uint16_t>(op.value & 0xFFFFu);
    if (!vstart_cmd_idx && regno == hybrid::regno_csr(0x008)) vstart_cmd_idx = i;
    if (!mcycle_cmd_idx && regno == hybrid::regno_csr(0xB00)) mcycle_cmd_idx = i;
  }
  REQUIRE(vstart_cmd_idx.has_value());
  REQUIRE(mcycle_cmd_idx.has_value());
  CHECK(*last_vle_idx < *vstart_cmd_idx);
  CHECK(*last_vle_idx < *mcycle_cmd_idx);
}

