// StateDrain is the dual of ResumeDriver: halt the hart via the Debug Module,
// read x1..x31 + DPC via Abstract Commands, populate hybrid_state_v1.

#include "hybrid/abstract_command.hpp"
#include "hybrid/resume_driver.hpp"
#include "hybrid/state_abi.h"
#include "hybrid/state_drain.hpp"
#include "recording_bus.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <optional>

#include <cstdint>

using hybrid::test::DmiOp;
using hybrid::test::kDmstatusHaltedAndAcked;
using hybrid::test::RecordingBus;
using RD = hybrid::ResumeDriver;

TEST_CASE("state_drain primes dmactive then issues haltreq before any read")
{
  RecordingBus bus;
  bus.dmstatus_value = kDmstatusHaltedAndAcked;

  hybrid::StateDrain drain(bus);
  (void) drain.drain();

  REQUIRE(bus.ops.size() >= 2);
  CHECK(bus.ops[0].kind == DmiOp::Kind::Write);
  CHECK(bus.ops[0].reg == RD::kDmcontrol);
  CHECK((bus.ops[0].value & RD::kDmcontrolDmactive) != 0u);
  CHECK((bus.ops[0].value & RD::kDmcontrolHaltreq) == 0u);

  CHECK(bus.ops[1].kind == DmiOp::Kind::Write);
  CHECK(bus.ops[1].reg == RD::kDmcontrol);
  CHECK((bus.ops[1].value & RD::kDmcontrolDmactive) != 0u);
  CHECK((bus.ops[1].value & RD::kDmcontrolHaltreq) != 0u);
}

