TEST_CASE("drain_with_passthrough with HYBRID_FLAG_V: PB dumps v0..v31 to scratch "
          "after the architectural counter/CSR reads")
{
  RecordingBus bus;
  bus.dmstatus_value = kDmstatusHaltedAndAcked;

  hybrid_state_v1 input{};
  input.magic   = HYBRID_STATE_MAGIC;
  input.version = HYBRID_STATE_VERSION;
  input.flags   = HYBRID_FLAG_RV64 | HYBRID_FLAG_V;
  input.priv    = 3;
  input.vlenb   = 64;

  hybrid::StateDrain drain(bus);
  (void) drain.drain_with_passthrough(input);

  // (a) every v0..v31 is dumped via a vse8.v executed in the Program Buffer.
  std::vector<int> missing;
  std::optional<std::size_t> first_vse_idx;
  for (uint16_t v = 0; v < 32; ++v) {
    const uint32_t want = hybrid::encode_vse8_v(static_cast<uint8_t>(v), 7);
    std::optional<std::size_t> at;
    for (std::size_t i = 0; i < bus.ops.size(); ++i) {
      const auto& op = bus.ops[i];
      if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
          && op.value == want) { at = i; break; }
    }
    if (!at) { missing.push_back(v); continue; }
    if (!first_vse_idx || *at < *first_vse_idx) first_vse_idx = at;
  }
  CHECK(missing.empty());
  REQUIRE(first_vse_idx.has_value());

  // (b) the dump sweep runs AFTER the mcycle/minstret reads, so the sweep's
  //     vse8.v insns (and any counter increments) cannot corrupt the drained
  //     counters. minstret(0xB02) is the last counter read before the sweep.
  std::optional<std::size_t> minstret_read_idx;
  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
    const auto& op = bus.ops[i];
    if (op.kind != DmiOp::Kind::Write || op.reg != RD::kCommand) continue;
    const auto regno   = static_cast<uint16_t>(op.value & 0xFFFFu);
    const bool is_read = ((op.value >> 16) & 1u) == 0u;
    if (is_read && regno == hybrid::regno_csr(0xB02)) minstret_read_idx = i;
  }
  REQUIRE(minstret_read_idx.has_value());
  CHECK(*minstret_read_idx < *first_vse_idx);
}

