  state.minstret = read_64bit_register(regno_csr(RD::kCsrMinstret));

  // V data regfile: dump v0..v31 to the shared scratch region via the
  // Program Buffer LAST -- after every architectural read above -- so the
  // sweep's clobbers (vtype/vl/vstart, x5/x6/x7) and its counter increments
