 *   x rides QEMU 1 -> vsim in its compiler-picked V register.
 *   y rides vsim   -> QEMU 2 in its compiler-picked V register.
 *
 *   The fixture never names a physical V register. The runtime helpers
 *   v_regfile_reload_all / v_regfile_dump_all (see v_regfile_xfer.h)
 *   save/restore the full 32-V-reg regfile bit-identically through
 *   V_SCRATCH at each boundary. Because every V reg's contents survive
 *   the round trip, the compiler's per-variable tracking ("x lives in
 *   v_compiler_choice") stays valid across enter_vsim and exit_vsim and
 *   the body of main() can be written in pure RVV intrinsics.
 *
 * Compiler hazard guard
 *   The empty asm volatile blocks with "vr" inputs ("force-live") pin
 *   the intrinsic-typed values in V regs at exact source points right
 *   before the boundary. Without them, the compiler may elide x's
 *   compute from phase 1 (treating it as dead before enter_vsim and
 *   re-emittable later) and the plugin would drain a wrong V regfile.
 *
 * VLEN contract: VLEN=512, e32 m1 -> 16 lanes per V reg. N=16.
 *
 * Phase-2 rule: no syscalls between enter_vsim and exit_vsim (vsim does
 * not implement semihosting).
 */
#include "runtime/rt_c_helpers.h"
#include "runtime/v_regfile_xfer.h"

#include <riscv_vector.h>
#include <stdint.h>
#include <stdio.h>

#define N 16

int main(void)
{
  const size_t vl = __riscv_vsetvl_e32m1((size_t) N);

  /* Phase 1 (QEMU 1): x = [1, 2, 3, ..., N] via vid + 1. */
  const vuint32m1_t vid_u = __riscv_vid_v_u32m1(vl);
  const vint32m1_t  x     = __riscv_vadd_vx_i32m1(
        __riscv_vreinterpret_v_u32m1_i32m1(vid_u), 1, vl);

  asm volatile("" : : "vr"(x));  /* force x live before drain */

  enter_vsim();
  v_regfile_reload_all();

  /* Phase 2 (vsim): 3-tap FIR convolution
   *   x_left[i]  = (i == 0)     ? 0 : x[i - 1]   (vslide1up)
   *   x_right[i] = (i == N - 1) ? 0 : x[i + 1]   (vslide1down)
   *   y[i]       = x_left[i] + 2 * x[i] + x_right[i] */
  const vint32m1_t x_left  = __riscv_vslide1up_vx_i32m1(x, 0, vl);
  const vint32m1_t x_right = __riscv_vslide1down_vx_i32m1(x, 0, vl);
  const vint32m1_t two_x   = __riscv_vsll_vx_i32m1(x, 1, vl);          /* 2*x */
  const vint32m1_t partial = __riscv_vadd_vv_i32m1(x_left, two_x, vl); /* x_left + 2x */
  const vint32m1_t y       = __riscv_vadd_vv_i32m1(partial, x_right, vl);

  asm volatile("" : : "vr"(y));  /* force y live before drain */

  v_regfile_dump_all();
  exit_vsim();

  /* Phase 3 (QEMU 2): store y and verify. */

